"""Build the auth-gated site (dm_site/) from dashboard_template.html.
Public shell = NO data; data served only by the token-verifying Netlify Function."""
import os, shutil
tpl=open('dashboard_template.html').read()

# 1) remove embedded DATA script tag
tpl=tpl.replace('<script id="DATA" type="application/json">__DATA__</script>\n','')
assert '__DATA__' not in tpl, 'DATA placeholder still present'

# 2) wrap the main app script body into boot(D)
assert "const D=JSON.parse(document.getElementById('DATA').textContent);" in tpl
tpl=tpl.replace("const D=JSON.parse(document.getElementById('DATA').textContent);","function boot(D){if(window.__booted)return;window.__booted=1;")

# 3) close boot() right after the final render(); then keep #toast; then inject auth gate
TAIL_OLD = 'render();\n</script>\n<div id="toast"></div>\n</body></html>'
assert TAIL_OLD in tpl, 'tail anchor not found'
AUTH = '''render();
window.dlCSV=dlCSV;window.openSheets=openSheets;window.setCohMode=setCohMode;window.toast=toast;window.setFilter=setFilter;
}
window.__boot=boot;
</script>
<div id="toast"></div>
<div id="authGate" style="position:fixed;inset:0;background:#F9FAFB;display:flex;align-items:center;justify-content:center;z-index:9999">
 <div style="text-align:center;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif;color:#1C252E">
  <img src="data:image/svg+xml;base64," alt="OpenHouse" style="width:210px;height:auto;display:block;margin:0 auto 10px">\n  <div style="font-size:20px;font-weight:800;color:#161C24;margin-bottom:6px">OH Demand Dashboard</div>
  <div style="color:#637381;font-size:13px;margin-bottom:22px">Sign in with your <b>@openhouse.in</b> Google account</div>
  <div id="gbtn" style="display:flex;justify-content:center"></div>
  <div id="authMsg" style="color:#FF5630;font-size:12px;margin-top:16px;min-height:16px"></div>
  <div id="authBusy" style="color:#637381;font-size:12px;margin-top:10px"></div>
 </div>
</div>
<script src="https://accounts.google.com/gsi/client" async defer></script>
<script>
var CLIENT_ID='548383854454-unmiq03djs8rhoqr9ot2747huthok1rj.apps.googleusercontent.com';
function onCred(resp){
 if(window.__authing)return;window.__authing=1;          // GSI can fire onCred twice — guard
 window.__cred=resp.credential;
 document.getElementById('authMsg').textContent='';
 document.getElementById('authBusy').textContent='Verifying & loading data…';
 fetch('/.netlify/functions/data',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({credential:resp.credential})})
  .then(function(r){return r.ok?r.json():r.json().then(function(e){return Promise.reject(e)})})
  .then(function(d){document.getElementById('authGate').style.display='none';window.__boot(d)})
  .catch(function(e){window.__authing=0;document.getElementById('authBusy').textContent='';
    document.getElementById('authMsg').textContent=(e&&e.error)?e.error:'Access denied. Use your @openhouse.in Google account.';});
}
function initGsi(){
 if(!window.google||!google.accounts){return setTimeout(initGsi,200);}
 google.accounts.id.initialize({client_id:CLIENT_ID,callback:onCred,hd:'openhouse.in',auto_select:false});
 google.accounts.id.renderButton(document.getElementById('gbtn'),{theme:'filled_blue',size:'large',text:'signin_with',shape:'pill'});
 try{google.accounts.id.prompt();}catch(e){}
}
window.addEventListener('load',initGsi);
</script>
</body></html>'''
tpl=tpl.replace(TAIL_OLD,AUTH)

os.makedirs('dm_site/public',exist_ok=True)
os.makedirs('dm_site/netlify/functions',exist_ok=True)
open('dm_site/public/index.html','w').write(tpl)
shutil.copy('/tmp/dm_dashboard_data.json','dm_site/netlify/functions/_data.json')
SA_FILE=os.environ.get('SA_FILE') or '/Users/akshit.chaudhary/Documents/Claude Code/Property level report/credentials/service_account.json'
shutil.copy(SA_FILE,'dm_site/netlify/functions/_sa.json')   # server-only; bundled in function, never in publish dir
open('dm_site/netlify.toml','w').write(
 '[build]\n  publish = "public"\n  command = ""\n\n[functions]\n  directory = "netlify/functions"\n  node_bundler = "esbuild"\n  included_files = ["netlify/functions/_data.json","netlify/functions/_sa.json"]\n')
print('shell:',os.path.getsize('dm_site/public/index.html'),'bytes |',
 'has boot(D):',('function boot(D){' in tpl),'| gsi:',('gsi/client' in tpl),
 '| no __DATA__:',('__DATA__' not in tpl),'| no embedded visits:', ('"visits":[' not in tpl))
